def solve(s: str) -> bool:
    st = []
    pairs = {')':'(', ']':'[', '}':'{'}
    for ch in s:
        if ch in '([{': st.append(ch)
        elif ch in ')]}':
            if not st or st.pop() != pairs[ch]: return False
    return len(st) == 0

