# C0666 · Merge sort (Intermedio, Algoritmos)
def solve(arr):
    if len(arr) <= 1:
        return arr
    mid = len(arr)//2
    left = solve(arr[:mid])
    right = solve(arr[mid:])
    out = []
    i=j=0
    while i < len(left) and j < len(right):
        if left[i] <= right[j]:
            out.append(left[i]); i += 1
        else:
            out.append(right[j]); j += 1
    out.extend(left[i:]); out.extend(right[j:])
    return out

